// Deduplicate council slugs — if multiple users track the same council, scrape it once.
const items = $input.all();
const seen = new Set();
const unique = [];

for (const item of items) {
  const slug = item.json.council_slug;
  if (slug && !seen.has(slug)) {
    seen.add(slug);
    unique.push({ json: { council_slug: slug } });
  }
}

return unique;

// Calculate date range: last 7 days in DD/MM/YYYY (what both portal types expect).
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

function fmt(d) {
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  return dd + '/' + mm + '/' + d.getFullYear();
}

const council = $input.first().json;

return [{
  json: {
    council_slug:  council.slug,
    council_name:  council.name,
    portal_url:    council.portal_url,
    portal_type:   council.portal_type || 'idox_search_do',
    date_from:     fmt(weekAgo),
    date_to:       fmt(now),
  }
}];

// Parse results from an Idox servlet portal (older style).
// Columns are positional — no CSS classes. Order:
//   0 application_number  1 received_date  2 valid_date
//   3 address             4 proposal       5 status/decision  6 decision_date

const html    = $input.first().json.data;
const context = $input.first().json;

if (!html || typeof html !== 'string') {
  return [{ json: { applications: [], council_slug: context.council_slug, parse_error: 'No HTML received' } }];
}

function stripTags(h) {
  return h
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/&#(\d+);/g, function(_, n) { return String.fromCharCode(Number(n)); })
    .replace(/<[^>]+>/g, '');
}

function parseAddress(cellHtml) {
  return stripTags(cellHtml)
    .split(/[\n,]+/)
    .map(function(s) { return s.trim(); })
    .filter(function(s) { return s.length > 0; })
    .join(', ');
}

function parseDate(cellHtml) {
  const text = stripTags(cellHtml).trim();
  const m = text.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  return m ? (m[3] + '-' + m[2] + '-' + m[1]) : null;
}

if (/your query did not return any results/i.test(html)) {
  return [{ json: { applications: [], council_slug: context.council_slug, scraped_count: 0 } }];
}

const tableStart = html.indexOf('<th><strong>Application number');
if (tableStart === -1) {
  return [{ json: { applications: [], council_slug: context.council_slug, parse_error: 'Results table not found' } }];
}

const tableOpenPos = html.lastIndexOf('<table', tableStart);
const tableEndPos  = html.indexOf('</table>', tableStart);
if (tableOpenPos === -1 || tableEndPos === -1) {
  return [{ json: { applications: [], council_slug: context.council_slug, parse_error: 'Table boundaries not found' } }];
}

const tableHtml  = html.slice(tableOpenPos, tableEndPos + 8);
const rowChunks  = tableHtml.split(/<tr[^>]*>/i).slice(1);
const applications = [];

for (var i = 0; i < rowChunks.length; i++) {
  const chunk = rowChunks[i];
  if (/<th/i.test(chunk) || chunk.indexOf('PKID=') === -1) continue;

  const cellChunks = chunk.split(/<td[^>]*>/i).slice(1);
  if (cellChunks.length < 6) continue;

  const cells    = cellChunks.map(function(c) { return c.replace(/<\/td>[\s\S]*/i, ''); });
  const refMatch = /<a[^>]+href="([^"]*PKID=[^"]*)"[^>]*>([^<]+)<\/a>/i.exec(cells[0]);
  if (!refMatch) continue;

  applications.push({
    reference:        refMatch[2].trim(),
    address:          parseAddress(cells[3]),
    description:      stripTags(cells[4]).trim(),
    status:           stripTags(cells[5]).trim(),
    application_date: parseDate(cells[1]),
    decision_date:    cells[6] ? parseDate(cells[6]) : null
  });
}

return [{ json: { council_slug: context.council_slug, applications: applications, scraped_count: applications.length } }];

// Parse results from a modern Idox search.do portal.
// Rows have CSS classes (odd/even). Fields identified by class name.

const html    = $input.first().json.data;
const context = $input.first().json;

if (!html || typeof html !== 'string') {
  return [{ json: { applications: [], council_slug: context.council_slug, parse_error: 'No HTML received' } }];
}

const applications = [];
const rowRegex = /<tr[^>]+class=["'](?:odd|even)["'][^>]*>([\s\S]*?)<\/tr>/gi;
let rowMatch;

while ((rowMatch = rowRegex.exec(html)) !== null) {
  const row = rowMatch[1];

  const refMatch = /<td[^>]*class=["'][^"']*number[^"']*["'][^>]*>[\s\S]*?<a[^>]*href=["']([^"']*)["'][^>]*>\s*([^<]+)\s*<\/a>/i.exec(row);
  if (!refMatch) continue;

  const addrMatch   = /<td[^>]*class=["'][^"']*address[^"']*["'][^>]*>([\s\S]*?)<\/td>/i.exec(row);
  const address     = addrMatch ? addrMatch[1].replace(/<[^>]+>/g, '').trim() : null;

  const descMatch   = /<td[^>]*class=["'][^"']*description[^"']*["'][^>]*>([\s\S]*?)<\/td>/i.exec(row);
  const description = descMatch ? descMatch[1].replace(/<[^>]+>/g, '').trim() : null;

  const statusMatch = /<td[^>]*class=["'][^"']*status[^"']*["'][^>]*>([\s\S]*?)<\/td>/i.exec(row);
  const status      = statusMatch ? statusMatch[1].replace(/<[^>]+>/g, '').trim() : null;

  const dateMatch   = /<td[^>]*class=["'][^"']*date[^"']*["'][^>]*>([\s\S]*?)<\/td>/i.exec(row);
  let application_date = null;
  if (dateMatch) {
    const raw   = dateMatch[1].replace(/<[^>]+>/g, '').trim();
    const parts = raw.match(/(\d{2})\/(\d{2})\/(\d{4})/);
    if (parts) application_date = parts[3] + '-' + parts[2] + '-' + parts[1];
  }

  applications.push({
    reference:        refMatch[2].trim(),
    address:          address,
    description:      description,
    status:           status,
    application_date: application_date,
    decision_date:    null
  });
}

return [{ json: { council_slug: context.council_slug, applications: applications, scraped_count: applications.length } }];

const item = $input.first().json;
if (!item.applications || item.applications.length === 0) {
  return [];
}
return [$input.first()];
